Rules.InvariantScript:
Patch(
    CommunityFirstAid,
    ThisItem,
    {
        Status: {Value: "Unassigned"},
        AssignedVolunteer: Blank(),
        AssignmentStatus: {Value: "Declined"}
    }
);

Patch(
    'Volunteer&Coordinator login',
    currentUser,
    {
        Availability: {Value: "Available"}
    }
);

Refresh(CommunityFirstAid);
Refresh('Volunteer&Coordinator login');
Notify("Assignment declined.", NotificationType.Success);

Set(selectedTask, ThisItem);

IfError(
    If(
        selectedTask.AssignmentStatus.Value = "Pending" &&
        CountRows(
            Filter(
                CommunityFirstAid,
                AssignedVolunteer = User().FullName &&
                Status.Value = "In Progress"
            )
        ) > 0,

        Notify("You already have an active task.", NotificationType.Warning),

        selectedTask.AssignmentStatus.Value = "Pending",

        Patch(
            CommunityFirstAid,
            selectedTask,
            {
                Status: {Value: "In Progress"},
                AssignmentStatus: {Value: "Accepted"},
                AssignedVolunteer: User().FullName
            }
        );

        Notify("Assignment accepted!", NotificationType.Success),

        selectedTask.Status.Value = "In Progress" &&
        selectedTask.AssignedVolunteer = User().FullName,

        Patch(
            'Volunteer&Coordinator login',
            LookUp(
                'Volunteer&Coordinator login',
                Email = currentUser.Email
            ),
            {
                Availability: {Value: "Available"}
            }
        );

        Patch(
            CommunityFirstAid,
            selectedTask,
            {
                Status: {Value: "Resolved"},
                AssignmentStatus: {Value: "Resolved"}
            }
        );

        Notify("Task resolved!", NotificationType.Success)
    ),

    Notify("Something went wrong. Please refresh.", NotificationType.Warning)
);

Refresh('Volunteer&Coordinator login');
Refresh(CommunityFirstAid);

Set(selectedTask, ThisItem);

IfError(
    If(
        selectedTask.Status.Value = "Unassigned" &&
        CountRows(
            Filter(
                CommunityFirstAid,
                AssignedVolunteer = User().FullName &&
                Status.Value = "In Progress"
            )
        ) > 0,

        Notify("You already have an active task.", NotificationType.Warning),

        selectedTask.Status.Value = "Unassigned",

        Patch(
            CommunityFirstAid,
            selectedTask,
            {
                Status: {Value: "In Progress"},
                AssignmentStatus: {Value: "Accepted"},
                AssignedVolunteer: User().FullName
            }
        );

        Patch(
            'Volunteer&Coordinator login',
            LookUp(
                'Volunteer&Coordinator login',
                Email = currentUser.Email
            ),
            {
                Availability: {Value: "Unavailable"}
            }
        );

        Notify("Assignment accepted!", NotificationType.Success),

        selectedTask.Status.Value = "In Progress" &&
        selectedTask.AssignedVolunteer = User().FullName,

        Patch(
            'Volunteer&Coordinator login',
            LookUp(
                'Volunteer&Coordinator login',
                Email = currentUser.Email
            ),
            {
                Availability: {Value: "Available"}
            }
        );

        Patch(
            CommunityFirstAid,
            selectedTask,
            {
                Status: {Value: "Resolved"},
                AssignmentStatus: {Value: "Resolved"}
            }
        );

        Notify("Task resolved!", NotificationType.Success)
    ),

    Notify("Something went wrong. Please refresh.", NotificationType.Warning)
);

Refresh('Volunteer&Coordinator login');
Refresh(CommunityFirstAid);

If(
    currentRole = "Volunteer",

    Set(currentPage, "Volunteer");
    Navigate('volunteer''s page'),

    Set(currentPage, "Coordinator");
    Navigate('coordinator''s page')
)

If(
    !IsBlank(currentUser),

    Set(currentUser, Blank());
    Set(currentRole, Blank());
    Set(currentPage, "User");
    Navigate('user''s page')
)
